external_knowledge:
- 'Most popular tracks' refers to tracks with the highest play counts and average ratings.; 
- The ranking is based on a combination of play counts and average ratings, giving precedence to play counts.; 
- 'Top three' means the tracks with the highest rankings based on the specified criteria.

sql:
SELECT COUNT(play_id) AS play_count
FROM play_history
WHERE user_id = '1' AND track_id = 1;

SELECT AVG(play_duration) AS average_play_duration
FROM play_history
WHERE city = 'New York';
